-- Seed initial analysis reports (authorId = null = public/system)
-- Slug uniqueness is enforced by the schema; INSERT OR IGNORE equivalent in Postgres uses ON CONFLICT DO NOTHING

INSERT INTO "Report" ("id", "title", "slug", "content", "category", "authorId", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid()::text,
  'Analiza UX modułów — problemy i propozycje ulepszeń',
  'ux-analysis',
  E'# Analiza UX modułów\n\n> Raport opisuje problemy UX, brakujące funkcjonalności i propozycje ulepszeń dla każdego modułu aplikacji WorldOfMag.\n\n---\n\n## Moduł Zakupy\n\n### Problemy\n\n- **Tworzenie listy używa `prompt()`** — natywne okno dialogowe przeglądarki. Na iOS Safari wygląda obco, nie pasuje do stylu aplikacji, nie da się go ostylować.\n- **Brak archiwizacji/zamykania listy** — po zrobieniu zakupów lista zostaje bez zmian. Nie ma sposobu na oznaczenie jej jako "ukończona" i schowanie z widoku.\n- **Brak przeciągnij i upuść** — kolejność produktów na liście jest niemożliwa do ręcznej zmiany.\n- **Sortowanie/filtrowanie** — dostępne, ale ukryte za ikoną; użytkownicy często go nie odkrywają.\n- **Ikony kategorii** — system SVG + emoji jest potężny, ale zbyt skomplikowany dla zwykłego użytkownika. Brakuje łatwego "quickstart".\n- **Brak zbiorczego "wyczyść zrobione"** na poziomie wszystkich list jednocześnie.\n\n### Propozycje\n\n1. Zastąpić `prompt()` modalem z inputem w stylu aplikacji.\n2. Przycisk "Zakończ zakupy" → archiwizuje listę (status `ARCHIVED`), przenosi do zakładki "Historia".\n3. Drag-and-drop dla produktów (biblioteka `@dnd-kit/sortable`).\n4. Ikony kategorii: uprościć do "wybierz emoji" w głównym widoku, zaawansowane SVG opcjonalnie.\n\n---\n\n## Moduł Zadania\n\n### Problemy\n\n- **Brak widoku "Dzisiaj"** — filtr po terminie istnieje, ale nie ma dedykowanego widoku zadań na dziś + zaległe.\n- **Brak grupowania projektów w jednym widoku** — każdy projekt to osobna podstrona, nie ma listy zbiorczej.\n- **Zadania cykliczne** — nieoczywista ikona, użytkownicy nie wiedzą że zadanie jest cykliczne.\n- **Edycja terminu** — wymaga otwarcia pełnego dialogu edycji; brakuje szybkiego inline-datepickera.\n- **Brak powiadomień push** — aplikacja nie przypomina o terminach.\n- **Priorytety** — 5 poziomów (NONE/LOW/MEDIUM/HIGH/URGENT) to za dużo; NONE i LOW są mylące.\n\n### Propozycje\n\n1. Widok "Dziś" jako domyślna strona główna Zadań.\n2. Widok listy wszystkich projektów z liczbą otwartych zadań.\n3. Wyraźna etykieta "🔁 cykliczne" przy tytule zadania.\n4. Kliknięcie w termin → mini datepicker bez otwierania pełnego dialogu.\n5. Uprościć priorytety do 4: BRAK / NISKI / ŚREDNI / WYSOKI / PILNY.\n\n---\n\n## Moduł Notatki\n\n### Problemy (krytyczne)\n\n- **Brak bezpieczeństwa** — do czasu migracji 0016 notatki nie miały właściciela. Każdy zalogowany użytkownik widział wszystkie notatki wszystkich użytkowników (NAPRAWIONE w tej wersji).\n- **Brak eksportu** — nie można wyeksportować notatki do pliku MD, TXT lub PDF.\n- **Brak widoku siatki** — jedyny widok to lista. Wizualny tryb kart byłby lepszy dla krótkich notatek.\n- **Wyszukiwanie** — działa, ale nie podświetla trafień w tekście.\n- **Grupy notatek** — globalne, nie per-użytkownik (do naprawy).\n- **Brak historii wersji** — zapisanie notatki zastępuje poprzednią zawartość bez możliwości cofnięcia.\n\n### Propozycje\n\n1. Eksport notatki (przycisk w menu notatki) → pobierz jako `.md`.\n2. Toggle widok lista/siatka w prawym górnym rogu.\n3. Podświetlanie trafień wyszukiwania (highlight) w liście i treści.\n4. Grupy notatek per-użytkownik (analogicznie do kategorii zakupów).\n\n---\n\n## Strona Główna (Home / AI Dashboard)\n\n### Problemy\n\n- **Beta-gated** — dostępna tylko dla roli `BETA_TESTER`. Nie wiadomo jak ją odblokować.\n- **QuickStats** — wyświetla statystyki, ale bez możliwości kliknięcia i przejścia do filtrowanego widoku.\n- **Dwa interfejsy AI** — `AICommandSection` na stronie głównej + globalny FAB `AICommandSheet`. Zduplikowana logika, różne UX.\n- **FAB zasłania treść** — na małych ekranach niebieski przycisk pokrywa prawą część interfejsu.\n\n### Propozycje\n\n1. Otworzyć Home dla wszystkich użytkowników (usunąć beta-gate lub zmienić na opt-in).\n2. QuickStats klikalny → link do odpowiedniej sekcji z filtrem.\n3. Ujednolicić AI: jeden interfejs (FAB globalny), usunąć sekcję z Home lub zamienić na showcase.\n4. FAB: na mobile przenieść wyżej, poza zasięg palca kciuka przy nawigacji.\n\n---\n\n## Panel Admina\n\n### Problemy\n\n- **Raporty tylko do odczytu** — do tej wersji nie można było tworzyć raportów z poziomu aplikacji. Wymagało to bezpośredniej ingerencji w bazę danych (NAPRAWIONE).\n- **Brak zarządzania jednostkami systemowymi** — hardkodowane w pliku TypeScript (`UNITS`), admin nie może dodać nowej jednostki bazowej.\n- **Dostęp do raportów** — wcześniej tylko dla adminów. Teraz raporty publiczne (authorId=null) są dostępne dla wszystkich przez `/reports`.\n\n### Propozycje\n\n1. Dodać sekcję "Jednostki systemowe" w panelu admina (analogicznie do kategorii systemowych).\n2. Raporty: formularz tworzenia nowego raportu bezpośrednio z UI.\n\n---\n\n## Ogólne tematy UX\n\n### Potwierdzenia destruktywnych akcji\nUsuwanie list, projektów, notatek odbywa się bez potwierdzenia. Jeden przypadkowy klik usuwa dane.\n**Propozycja:** Modal potwierdzenia dla: delete list, delete project, delete note, clear done items.\n\n### Brak operacji zbiorczych\nW żadnym module nie można zaznaczyć wielu elementów i wykonać akcji grupowej.\n**Propozycja:** Multi-select (długie naciśnięcie na mobile, checkbox na desktop) + batch delete/status change.\n\n### Spójność skrótów klawiszowych\nSkróty j/k/x/e/d są zdefiniowane w `useKeyboardShortcuts.ts` ale działają tylko w Shopping. Zadania i Notatki nie mają pełnej obsługi klawiatury.\n**Propozycja:** Ujednolicić hook skrótów dla wszystkich modułów.\n\n### Responsywność na tabletach\nAplikacja jest optymalizowana pod mobile (<768px) i desktop (>768px). Na tabletach w orientacji poziomej sidebar jest widoczny, ale zawartość wygląda dziwnie szeroko.\n**Propozycja:** Breakpoint `lg:` (1024px) dla pełnego layoutu desktopowego.\n',
  'ux',
  NULL,
  NOW(),
  NOW()
)
ON CONFLICT ("slug") DO NOTHING;

INSERT INTO "Report" ("id", "title", "slug", "content", "category", "authorId", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid()::text,
  'Propozycje nowych modułów aplikacji',
  'new-modules-proposal',
  E'# Propozycje nowych modułów\n\n> Analiza możliwych rozszerzeń WorldOfMag — modułów wspierających codzienne życie osobiste i rodzinne.\n\n---\n\n## Kryterium wyboru\n\nKażdy proponowany moduł musi spełniać co najmniej dwa z trzech kryteriów:\n1. **Codzienne użycie** — przydatny przynajmniej raz w tygodniu\n2. **Synergia** — integruje się z istniejącymi modułami (np. Zakupy, Zadania)\n3. **Wartość zespołowa** — przydatny dla całej rodziny/teamu, nie tylko jednej osoby\n\n---\n\n## 1. Budżet i Finanse ⭐⭐⭐\n\n**Opis:** Śledzenie wydatków, planowanie budżetu domowego, kategorie wydatków.\n\n**Funkcjonalności:**\n- Dodawanie wydatków z kategorią, kwotą, datą i notatką\n- Miesięczny budżet per kategoria\n- Wykresy wydatków (słupkowy, kołowy)\n- Wspólny budżet teamu/rodziny\n- Eksport CSV\n\n**Synergia:** Zakupy → automatyczne przenoszenie zrealizowanej listy do wydatków. Zadania → "zapłać fakturę".\n\n**Priorytet: Wysoki** — finanse to jeden z najczęstszych powodów używania aplikacji do zarządzania.\n\n---\n\n## 2. Nawyki (Habit Tracker) ⭐⭐⭐\n\n**Opis:** Budowanie nawyków przez codzienne śledzenie z wizualizacją w formie kalendarza.\n\n**Funkcjonalności:**\n- Definiowanie nawyków (nazwa, ikona, częstotliwość)\n- Zaznaczanie wykonania (tap = zrobione)\n- Pasek postępu i streak (seria dni z rzędu)\n- Widok tygodniowy/miesięczny (GitHub contributions style)\n- Powiadomienia przypominające\n\n**Synergia:** Integracja z Zadaniami (nawyk może generować cykliczne zadanie).\n\n**Priorytet: Wysoki** — popularna kategoria, wyróżnia aplikację od zwykłego todo-lista.\n\n---\n\n## 3. Receptury i Kuchnia ⭐⭐\n\n**Opis:** Baza przepisów z możliwością przeniesienia składników bezpośrednio do listy zakupów.\n\n**Funkcjonalności:**\n- Dodawanie przepisów (składniki z ilościami + kroki)\n- "Zrób zakupy do tego przepisu" → przenosi składniki do wybranej listy zakupów\n- Tagi (wegetariańskie, szybkie <30min, itp.)\n- Planowanie posiłków na tydzień\n- Wspólna baza receptur teamu\n\n**Synergia:** Ścisła integracja z Zakupami — "killer feature" dla rodzin.\n\n**Priorytet: Średni** — wymaga dużo pracy nad UX dodawania przepisów.\n\n---\n\n## 4. Dokumenty i Ważne Pliki ⭐⭐\n\n**Opis:** Przechowywanie ważnych dokumentów: ubezpieczenia, gwarancje, umowy, skany.\n\n**Funkcjonalności:**\n- Upload plików (PDF, zdjęcia)\n- Kategoryzacja (dom, praca, zdrowie, finanse)\n- Daty ważności z przypomnieniami\n- Notatki do każdego dokumentu\n- Wyszukiwanie full-text\n- Udostępnianie w teamie\n\n**Synergia:** Notatki (tekstowa wersja), Zadania (przypomnienie o odnowieniu ubezpieczenia).\n\n**Priorytet: Średni** — wymaga rozwiązania kwestii storage (pliki binarne).\n\n---\n\n## 5. Zdrowie i Samopoczucie ⭐⭐\n\n**Opis:** Śledzenie parametrów zdrowotnych, leków i wizyt lekarskich.\n\n**Funkcjonalności:**\n- Dziennik leków (nazwa, dawka, godziny przyjmowania)\n- Parametry zdrowotne (waga, ciśnienie, glukoza) z wykresem trendu\n- Terminarz wizyt lekarskich\n- Historia pomiarów\n- Wspólne śledzenie dla rodziny (np. dzieci)\n\n**Synergia:** Zadania (przypomnienie o wizycie), Finanse (koszt leków).\n\n**Priorytet: Średni** — wrażliwe dane wymagają dodatkowej ostrożności (szyfrowanie).\n\n---\n\n## 6. Kontakty i CRM Osobisty ⭐\n\n**Opis:** Mini-baza kontaktów z notatkami, urodzinami i historią interakcji.\n\n**Funkcjonalności:**\n- Kontakty z polami: imię, email, telefon, urodziny, notatki\n- Powiadomienie o urodzinach\n- Historia ostatnich kontaktów ("ostatnio rozmawiałem 3 miesiące temu")\n- Grupy kontaktów\n\n**Synergia:** Zadania ("oddzwoń do Kowalskiego"), Zaproszenia do teamu.\n\n**Priorytet: Niski** — overlap z istniejącymi aplikacjami kontaktów.\n\n---\n\n## 7. Projekty Osobiste / Cele (OKR-lite) ⭐\n\n**Opis:** Definiowanie celów z mierzalnymi krokami milowymi i paskiem postępu.\n\n**Funkcjonalności:**\n- Cel z datą realizacji i opisem\n- Klucze wynikowe (measurable milestones)\n- Automatyczny postęp na podstawie powiązanych Zadań\n- Widok roczny/kwartalny\n\n**Synergia:** Ścisła integracja z Zadaniami (zadania podpięte pod cel).\n\n**Priorytet: Niski** — nakłada się z istniejącymi Projektami w module Zadań.\n\n---\n\n## Rekomendacja implementacji\n\n| Priorytet | Moduł | Szacowany nakład |\n|-----------|-------|------------------|\n| 1 | Budżet i Finanse | 2-3 tygodnie |\n| 2 | Nawyki | 1-2 tygodnie |\n| 3 | Receptury i Kuchnia | 2-3 tygodnie |\n| 4 | Dokumenty | 1-2 tygodnie + storage |\n| 5 | Zdrowie | 2 tygodnie |\n',
  'proposal',
  NULL,
  NOW(),
  NOW()
)
ON CONFLICT ("slug") DO NOTHING;

INSERT INTO "Report" ("id", "title", "slug", "content", "category", "authorId", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid()::text,
  'Wizja modułów Calendar i Work',
  'calendar-work-vision',
  E'# Wizja modułów Calendar i Work\n\n> Opis planowanej funkcjonalności dla dwóch nieaktywnych modułów widocznych w menu aplikacji.\n\n---\n\n## Moduł Calendar\n\n### Cel\n\nCalendar to centralny hub planowania czasowego — integruje wszystkie moduły WorldOfMag w widoku kalendarza. Nie jest kolejną apką kalendarza, ale widokiem istniejących danych z perspektywy czasu.\n\n### Widoki\n\n- **Miesiąc** — klasyczny widok miesięczny, komórki z liczbą wydarzeń/zadań\n- **Tydzień** — timeline 7 dni z blokami czasowymi\n- **Dzień** — szczegółowy widok z godzinami\n- **Agenda** — chronologiczna lista nadchodzących wydarzeń\n\n### Źródła danych (integracje)\n\n| Źródło | Co pokazuje |\n|--------|-------------|\n| Zadania | Terminy (`dueDate`) i daty startowe (`startDate`) |\n| Zakupy | Planowane "dni zakupów" (opcjonalne przypięcie listy do daty) |\n| Nawyki (przyszłość) | Zaplanowane nawyki |\n| Zdrowie (przyszłość) | Terminy wizyt lekarskich |\n| Własne wydarzenia | Jednorazowe lub cykliczne wpisy kalendarza |\n\n### Własne Wydarzenie (Event)\n\nNowy model `Event`:\n- Tytuł, opis, data/godzina (start + koniec)\n- Całodniowe lub z godziną\n- Cykliczność (jak w Zadaniach)\n- Kolor/kategoria\n- Uczestnicze z teamu\n\n### Synchronizacja CalDAV\n\nOpcjonalna integracja z zewnętrznymi kalendarzami (Google Calendar, Apple Calendar) przez protokół CalDAV.\n- Import wydarzeń zewnętrznych (tylko do odczytu w pierwszej wersji)\n- Eksport terminów zadań do kalendarza zewnętrznego\n\n### UX na mobile\n\nNa smartfonie kalendarz miesięczny zmienia się w widok "Agenda" z podziałem na dni — bardziej czytelne od siatki kalendarza na małym ekranie.\n\n---\n\n## Moduł Work\n\n### Cel\n\nWork to zestaw narzędzi dla freelancerów i osób pracujących na własny rachunek — śledzenie czasu, klientów i przychodów. Nie jest to korporacyjne narzędzie PM, ale prosty tracker dla jednej osoby.\n\n### Funkcjonalności\n\n#### 1. Śledzenie czasu (Time Tracking)\n\n- Przycisk START/STOP na zadaniu → mierzy czas pracy\n- Historia wpisów czasu z opisem i tagiem projektu/klienta\n- Raport tygodniowy: ile godzin per klient\n- Integracja z modułem Zadania: czas logowany per zadanie\n\n#### 2. Klienci\n\n- Lista klientów z nazwą, kontaktem, stawką godzinową\n- Każdy projekt Tasks może być przypisany do klienta\n- Widok: klient → projekty → zadania → zalogowany czas\n\n#### 3. Faktury (uproszczone)\n\n- Generowanie faktury na podstawie zalogowanego czasu + stawki\n- Format: PDF lub prosty widok do wydruku\n- Statusy faktury: Robocza / Wysłana / Opłacona\n\n#### 4. Raporty\n\n- Podsumowanie godzin w miesiącu per klient\n- Szacowane przychody vs rzeczywiste\n- Eksport do CSV\n\n### Model danych (nowe tabele)\n\n```\nClient        — klienci\nTimeEntry     — wpisy czasu (taskId, clientId, minutes, description, date)\nInvoice       — faktury (clientId, period, totalMinutes, rate, status)\nInvoiceItem   — pozycje faktury\n```\n\n### UX\n\n- Timer widoczny jako stały pasek na górze gdy aktywny (jak Spotify Now Playing)\n- Szybki start timera z command palette (Ctrl+K)\n- Na mobile: widget timera w menu hamburgera\n\n### Kiedy implementować\n\nWork jest modułem niszowym — przydatny głównie dla freelancerów. Rekomendacja: **implementować po Kalendarzu**, gdyż Work wymaga integracji z czasem (Calendar) i Zadaniami.\n',
  'proposal',
  NULL,
  NOW(),
  NOW()
)
ON CONFLICT ("slug") DO NOTHING;

INSERT INTO "Report" ("id", "title", "slug", "content", "category", "authorId", "createdAt", "updatedAt")
VALUES (
  gen_random_uuid()::text,
  'Analiza i plan ulepszenia systemu poleceń AI',
  'llm-command-analysis',
  E'# Analiza i plan ulepszenia systemu poleceń AI\n\n> Raport opisuje aktualny stan "magicznej ikony" (✨) — systemu AI interpretującego polecenia naturalne — oraz proponuje konkretne ulepszenia.\n\n---\n\n## Stan aktualny\n\n### Architektura\n\nSystem składa się z dwóch endpointów:\n\n1. **`/api/llm/home/interpret`** — przyjmuje tekst od użytkownika, wysyła do Groq (llama-3.1-8b-instant), zwraca tablicę `AIAction[]`\n2. **`/api/llm/home/execute`** — przyjmuje potwierdzone akcje, wykonuje je w bazie danych\n\n**Komponenty UI:**\n- `AICommandSheet` — globalny FAB (floating action button) w prawym dolnym rogu, dostępny na wszystkich stronach\n- `ActionDrawer` — modal z listą wykrytych akcji do zatwierdzenia\n- `AICommandSection` — sekcja na stronie głównej (Home), duplikuje funkcjonalność FAB\n\n### Obsługiwane moduły i akcje\n\n| Moduł | Akcje |\n|-------|-------|\n| shopping | add_item, update_item_status, delete_item |\n| tasks | create_task, shift_task_due_date, update_task_status |\n| notes | create_note, append_to_note |\n\n### Wykryte problemy (naprawione w tej wersji)\n\n1. **Brak filtrowania po użytkowniku w `append_to_note`** — zapytanie przeszukiwało notatki wszystkich użytkowników. Użytkownik A mógł dopisać treść do notatki użytkownika B. **NAPRAWIONE.**\n2. **Brak audit logu dla akcji LLM** — akcje wykonane przez AI nie były logowane w `UserActivity`. **NAPRAWIONE** — każda wykonana akcja jest teraz logowana jako `module: "llm"`.\n\n---\n\n## Planowane ulepszenia\n\n### 1. Edycja parametrów przed wykonaniem ✅ (zaimplementowane)\n\nW `ActionDrawer` każda akcja teraz pokazuje przycisk "Parametry" rozwijający listę pól edytowalnych. Użytkownik może zmienić np. nazwę produktu, priorytet zadania lub treść dopisywaną do notatki przed kliknięciem "Wykonaj".\n\n### 2. Sprawdzanie uprawnień\n\nObecnie każdy zalogowany użytkownik może wywoływać wszystkie akcje na swoich danych. Brakuje sprawdzenia:\n- Czy użytkownik ma uprawnienie do danego modułu (gdy RBAC to ogranicza)\n- Blokady akcji adminowych dla zwykłych użytkowników\n\n**Plan:** W `/execute` przed wywołaniem `executeAction` sprawdzić `hasPermission(session, requiredPermission)` dla akcji wymagających specjalnych uprawnień.\n\n### 3. Rozszerzenie na więcej modułów\n\nAktualne 3 moduły to ułamek możliwości. Potencjalne rozszerzenia:\n\n| Moduł | Przykładowe polecenie |\n|-------|----------------------|\n| lists | "utwórz nową listę zakupów o nazwie Urodziny" |\n| task_projects | "nowy projekt o nazwie Remont kuchni" |\n| categories | "dodaj kategorię Elektronika z ikoną 💻" |\n| notes groups | "przenieś notatkę X do grupy Praca" |\n\n### 4. Kontekst teamu\n\nGdy użytkownik przebywa na liście zakupów teamu, akcja `add_item` powinna domyślnie dodawać do tej listy, a nie do listy osobistej.\n\n**Plan:** Przekazywać `activeTeamId` w kontekście, podobnie jak aktualnie przekazywany jest `activeListId`.\n\n### 5. Ujednolicenie interfejsów\n\n`AICommandSection` na stronie głównej i `AICommandSheet` FAB to dwa oddzielne interfejsy z podobną logiką. Należy:\n- Usunąć `AICommandSection` lub przekształcić w showcase (statyczny opis)\n- FAB jako jedyny punkt wejścia do poleceń AI\n- Kontekst modułu automatycznie z aktywnej trasy (już działa)\n\n### 6. Feedback jakości parsowania\n\nGdy LLM źle zinterpretuje polecenie, użytkownik nie może poprosić o re-parsowanie. Należy dodać przycisk "Interpretuj ponownie" w `ActionDrawer`, który wysyła pierwotny tekst z powrotem do `/interpret`.\n\n---\n\n## Metryki do monitorowania\n\nPo wdrożeniu audit logu (`UserActivity.module = "llm"`) można śledzić:\n- Najczęstsze typy akcji\n- Wskaźnik błędów (sukces vs. porażka per typ akcji)\n- Moduły najczęściej używane przez AI\n- Akcje anulowane przez użytkownika (zaznaczone ale nie wykonane)\n',
  'architecture',
  NULL,
  NOW(),
  NOW()
)
ON CONFLICT ("slug") DO NOTHING;
